mapper.update:
UPDATE conversations
SET status = 'running',
    active_run_id = #{activeRunId},
    last_activity_at = #{lastActivityAt},
    updated_at = #{updatedAt}
WHERE id = #{id}

UPDATE conversations
SET status = 'waiting_for_user',
    pending_question_message_id = #{pendingQuestionMessageId},
    last_activity_at = #{lastActivityAt},
    updated_at = #{updatedAt}
WHERE id = #{id}

UPDATE conversations
SET active_run_id = NULL,
    last_activity_at = #{lastActivityAt},
    updated_at = #{updatedAt}
WHERE id = #{id}
